Ini adalah modul Python untuk audit keamanan konfigurasi Nginx. Jangan hanya mengandalkan sintaks valid; konfigurasi yang valid secara sintaks bisa saja rentan secara keamanan. Modul ini melakukan parsing dasar dan validasi terhadap praktik keamanan standar PT Sherif Network.

### `nginx_security_audit.py`

```python
import re
import sys
from typing import List, Dict, Tuple
from dataclasses import dataclass

@dataclass
class SecurityIssue:
    severity: str  # CRITICAL, HIGH, MEDIUM, LOW
    directive: str
    message: str
    line_number: int

class NginxConfigParser:
    def __init__(self, content: str):
        self.content = content
        self.lines = content.splitlines()
        self.issues: List[SecurityIssue] = []

    def parse_blocks(self) -> List[Dict]:
        """
        Parsing dasar untuk struktur block Nginx.
        Tidak menggunakan library eksternal untuk meminimalkan dependency.
        """
        # Implementasi parser sederhana untuk mengekstrak blok server/location
        # Ini bukan parser lengkap RFC, tapi cukup untuk audit keamanan dasar
        blocks = []
        stack = []
        current_block = {}

        # Regex untuk mendeteksi awal blok
        block_pattern = re.compile(r'^\s*(\w+)\s+(.*?)\s*\{')
        # Regex untuk directive
        directive_pattern = re.compile(r'^\s*(\w+)\s+(.+);')

        for idx, line in enumerate(self.lines):
            clean_line = line.strip()
            if not clean_line or clean_line.startswith('#'):
                continue

            block_match = block_pattern.match(clean_line)
            if block_match:
                block_name = block_match.group(1)
                block_args = block_match.group(2)
                new_block = {'type': block_name, 'args': block_args, 'children': [], 'line': idx + 1}
                if stack:
                    stack[-1]['children'].append(new_block)
                else:
                    blocks.append(new_block)
                stack.append(new_block)
                continue

            if clean_line == '}':
                if stack:
                    stack.pop()
                continue

            dir_match = directive_pattern.match(clean_line)
            if dir_match and stack:
                stack[-1]['children'].append({
                    'type': 'directive',
                    'key': dir_match.group(1),
                    'value': dir_match.group(2),
                    'line': idx + 1
                })

        return blocks

class NginxSecurityValidator:
    def __init__(self, parser: NginxConfigParser):
        self.parser = parser
        self.issues = []

    def validate(self, blocks: List[Dict]):
        """Menjalankan semua check keamanan."""
        self.check_server_tokens(blocks)
        self.check_ssl_protocols(blocks)
        self.check_autoindex(blocks)
        self.check_sensitive_files(blocks)
        self.check_ssrf_risks(blocks)
        return self.issues

    def add_issue(self, severity: str, directive: str, message: str, line: int):
        self.issues.append(SecurityIssue(severity, directive, message, line))

    def check_server_tokens(self, blocks: List[Dict]):
        # Cek global dan per server block
        found_off = False
        for block in blocks:
            if block['type'] == 'http':
                for child in block.get('children', []):
                    if child.get('type') == 'directive' and child['key'] == 'server_tokens':
                        if child['value'] == 'off':
                            found_off = True
            elif block['type'] == 'server':
                # Jika tidak ada setting di server block, bergantung pada http block
                pass

        # Simplifikasi: Jika tidak ditemukan 'server_tokens off' di level http, flagging
        # Ideally need recursive search, here we do flat check for demo
        content = "\n".join(self.parser.lines)
        if 'server_tokens' not in content or 'server_tokens on' in content:
            self.add_issue('MEDIUM', 'server_tokens', 'Server version should be hidden (server_tokens off).', 0)

    def check_ssl_protocols(self, blocks: List[Dict]):
        """Memastikan hanya TLSv1.2 dan TLSv1.3 yang digunakan."""
        weak_protocols = ['SSLv3', 'TLSv1', 'TLSv1.1']
        content = "\n".join(self.parser.lines)

        for proto in weak_protocols:
            if proto in content:
                # Cek apakah ada di dalam konteks ssl_protocols
                if re.search(r'ssl_protocols\s+.*' + proto, content):
                    self.add_issue('HIGH', 'ssl_protocols', f'Weak protocol detected: {proto}. Use TLSv1.2 TLSv1.3 only.', 0)

    def check_autoindex(self, blocks: List[Dict]):
        """Directory listing harus dimatikan."""
        content = "\n".join(self.parser.lines)
        if re.search(r'autoindex\s+on', content):
            self.add_issue('HIGH', 'autoindex', 'Directory listing is enabled. This leaks file structure.', 0)

    def check_sensitive_files(self, blocks: List[Dict]):
        """Mendeteksi apakah akses ke file sensitif diblokir."""
        sensitive_patterns = [r'\.git', r'\.env', r'\.htaccess', r'\.swp']
        content = "\n".join(self.parser.lines)

        # Cek apakah ada location block yang deny akses ke pattern ini
        has_protection = False
        for pattern in sensitive_patterns:
            if re.search(r'location\s+~\s*' + pattern, content):
                if re.search(r'deny\s+all', content):
                    has_protection = True

        if not has_protection:
            self.add_issue('CRITICAL', 'location', 'No explicit deny rules found for sensitive files (.git, .env, etc).', 0)

    def check_ssrf_risks(self, blocks: List[Dict]):
        """Mencegah proxy_pass ke internal network (SSRF)."""
        # Deteksi proxy_pass yang mengarah ke localhost atau IP privat tanpa validasi
        dangerous_ips = ['127.0.0.1', 'localhost', '192.168.', '10.0.', '172.16.']
        content = "\n".join(self.parser.lines)

        for ip in dangerous_ips:
            if re.search(r'proxy_pass\s+.*' + ip, content):
                self.add_issue('HIGH', 'proxy_pass', f'Potential SSRF risk: proxy_pass to internal address ({ip}).', 0)

def run_audit(file_path: str):
    try:
        with open(file_path, 'r') as f:
            content = f.read()
    except FileNotFoundError:
        print(f"[ERROR] File {file_path} tidak ditemukan.")
        sys.exit(1)
    except PermissionError:
        print(f"[ERROR] Tidak ada izin membaca {file_path}.")
        sys.exit(1)

    parser = NginxConfigParser(content)
    blocks = parser.parse_blocks()
    validator = NginxSecurityValidator(parser)
    issues = validator.validate(blocks)

    print(f"--- AUDIT RESULT: {file_path} ---")
    if not issues:
        print("[OK] Tidak ada isu keamanan umum yang terdeteksi.")
    else:
        for issue in issues:
            print(f"[{issue.severity}] Line {issue.line}: {issue.directive} - {issue.message}")

    print("---------------------------------")

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python nginx_security_audit.py <nginx.conf>")
        sys.exit(1)
    run_audit(sys.argv[1])
```

