```python
import os
import sys
from typing import Any, Dict, List, Optional, Union
from functools import wraps

class SecureEnvLoader:
    def __init__(self, schema: Dict[str, Dict], env_file: Optional[str] = None):
        """
        Inisialisasi loader dengan schema validasi ketat.
        :param schema: Dict containing var name, type, required status, and sensitivity.
                       Example: {'DB_PASSWORD': {'type': str, 'required': True, 'sensitive': True}}
        :param env_file: Path to .env file (optional, prioritizes os.environ)
        """
        self._config: Dict[str, Any] = {}
        self._schema = schema
        self._loaded = False

        if env_file:
            self._load_from_file(env_file)

        self._validate_and_load()
        self._loaded = True

    def _load_from_file(self, path: str):
        """Load variables from file if os.environ is empty."""
        if not os.path.isfile(path):
            return

        with open(path, 'r') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#') and '=' in line:
                    key, value = line.split('=', 1)
                    os.environ.setdefault(key.strip(), value.strip())

    def _validate_and_load(self):
        """Validasi tipe dan keberadaan variable. Fail-closed jika critical var hilang."""
        for var_name, rules in self._schema.items():
            value = os.environ.get(var_name)
            is_required = rules.get('required', False)
            var_type = rules.get('type', str)

            if value is None:
                if is_required:
                    raise SecurityError(f"Missing required environment variable: {var_name}")
                continue

            try:
                if var_type == bool:
                    parsed_value = value.lower() in ('true', '1', 'yes')
                elif var_type == int:
                    parsed_value = int(value)
                elif var_type == float:
                    parsed_value = float(value)
                else:
                    parsed_value = str(value)

                self._config[var_name] = parsed_value
            except ValueError:
                raise SecurityError(f"Type mismatch for {var_name}. Expected {var_type.__name__}")

    def get(self, key: str, default: Any = None) -> Any:
        """Ambil nilai config dengan aman."""
        if not self._loaded:
            raise SecurityError("Configuration not loaded")
        return self._config.get(key, default)

    def __getattr__(self, item: str) -> Any:
        """Akses attribute langsung, tapi tetap aman."""
        if item in self._config:
            return self._config[item]
        raise AttributeError(f"SecureEnvLoader has no attribute '{item}'")

    def __repr__(self) -> str:
        """Mencegah kebocoran secret saat debug/logging."""
        safe_items = []
        for key, value in self._config.items():
            is_sensitive = self._schema.get(key, {}).get('sensitive', False)
            if is_sensitive:
                safe_items.append(f"{key}='***REDACTED***'")
            else:
                safe_items.append(f"{key}={value}")
        return f"SecureEnvLoader({', '.join(safe_items)})"

    def __setattr__(self, key, value):
        """Mencegah modifikasi konfigurasi setelah inisialisasi (Immutability)."""
        if key in ['_config', '_schema', '_loaded']:
            super().__setattr__(key, value)
        else:
            if hasattr(self, '_loaded') and self._loaded:
                raise SecurityError("Configuration is immutable after load")
            super().__setattr__(key, value)

class SecurityError(Exception):
    """Custom exception untuk kegagalan keamanan konfigurasi."""
    pass

# --- Contoh Penggunaan ---
if __name__ == "__main__":
    schema = {
        'APP_ENV': {'type': str, 'required': True, 'sensitive': False},
        'DB_PORT': {'type': int, 'required': True, 'sensitive': False},
        'API_SECRET': {'type': str, 'required': True, 'sensitive': True},
        'DEBUG_MODE': {'type': bool, 'required': False, 'sensitive': False}
    }

    try:
        # Pastikan variable environment sudah diset sebelum running
        config = SecureEnvLoader(schema)
        print(config)  # API_SECRET akan ter-redact
        print(f"Port: {config.get('DB_PORT')}")
    except SecurityError as e:
        print(f"CRITICAL: {e}", file=sys.stderr)
        sys.exit(1)
```

### Analisis Keamanan Implementasi

1.  **Fail-Closed Strategy**: Jika variable wajib (`required: True`) tidak ditemukan, aplikasi akan berhenti (`sys.exit(1)`). Ini mencegah aplikasi berjalan dalam kondisi rentan karena konfigurasi yang hilang.
2.  **Type Validation**: Mencegah injection melalui konfigurasi. Misalnya, `DB_PORT` dipaksa menjadi `int`. Jika user memasukkan string berbahaya, aplikasi gagal saat startup, bukan saat runtime.
3.  **Secret Masking**: Method `__repr__` secara otomatis menyembunyikan variable yang ditandai `sensitive: True`. Ini mencegah kebocoran secret saat object tidak sengaja di-print ke log server.
4.  **Immutability**: Setelah loaded, konfigurasi tidak bisa diubah (`__setattr__` override). Mencegah runtime manipulation oleh kode yang terkompromi.
5.  **No Hardcoded Fallback**: Tidak ada nilai default untuk variable sensitif. Jika tidak ada, sistem error.

### Rekomendasi Tambahan

*   **.gitignore**: Pastikan file `.env` masuk dalam `.gitignore`. Jangan pernah commit secret ke repository.
*   **Permissions**: Set permission file `.env` menjadi `600` (`chmod 600 .env`) di server produksi.
*   **Secrets Management**: Untuk skala enterprise, jangan gunakan `.env`. Gunakan AWS Secrets Manager, HashiCorp Vault, atau Kubernetes Secrets. Kelas ini hanya valid untuk lingkungan kecil/menengah.
